[data-theme="light"] .command-palette-input-row { border-bottom-color: #d0d7de; }
[data-theme="light"] .command-palette-item-desc { color: #8b949e; }
[data-theme="light"] .command-palette-item-shortcut { color: #8b949e; }
[data-theme="light"] .command-palette-item-shortcut kbd { background: #eaeef2; }
